func TestCompactDiffFormatterMixed(t *testing.T) {
	plan := &plans.Plan{
		Changes: &plans.ChangesSrc{
			Resources: []*plans.ResourceInstanceChangeSrc{
				{
					Addr: addrs.Resource{
						Mode: addrs.ManagedResourceMode,
						Type: "aws_instance",
						Name: "create_example",
					}.Instance(addrs.NoKey).Absolute(addrs.RootModuleInstance),
					ProviderAddr: addrs.AbsProviderConfig{
						Module:   addrs.RootModule,
						Provider: addrs.NewDefaultProvider("aws"),
					},
					ChangeSrc: plans.ChangeSrc{
						Action: plans.Create,
					},
				},
				{
					Addr: addrs.Resource{
						Mode: addrs.ManagedResourceMode,
						Type: "aws_instance",
						Name: "update_example",
					}.Instance(addrs.NoKey).Absolute(addrs.RootModuleInstance),
					ProviderAddr: addrs.AbsProviderConfig{
						Module:   addrs.RootModule,
						Provider: addrs.NewDefaultProvider("aws"),
					},
					ChangeSrc: plans.ChangeSrc{
						Action: plans.Update,
					},
				},
				{
					Addr: addrs.Resource{
						Mode: addrs.ManagedResourceMode,
						Type: "aws_subnet",
						Name: "delete_example",
					}.Instance(addrs.NoKey).Absolute(addrs.RootModuleInstance),
					ProviderAddr: addrs.AbsProviderConfig{
						Module:   addrs.RootModule,
						Provider: addrs.NewDefaultProvider("aws"),
					},
					ChangeSrc: plans.ChangeSrc{
						Action: plans.Delete,
					},
				},
				{
					Addr: addrs.Resource{
						Mode: addrs.ManagedResourceMode,
						Type: "aws_security_group",
						Name: "example",
					}.Instance(addrs.NoKey).Absolute(addrs.RootModuleInstance),
					ProviderAddr: addrs.AbsProviderConfig{
						Module:   addrs.RootModule,
						Provider: addrs.NewDefaultProvider("aws"),
					},
					ChangeSrc: plans.ChangeSrc{
						Action: plans.DeleteThenCreate,
					},
				},
			},
		},
	}

	formatter := &CompactDiffFormatter{}
	result := formatter.Format(plan, nil)

	if !strings.Contains(result, "# Create") {
		t.Fatalf("expected '# Create' in output")
	}

	if !strings.Contains(result, "# Update") {
		t.Fatalf("expected '# Update' in output")
	}

	if !strings.Contains(result, "# Replace") {
		t.Fatalf("expected '# Replace' in output")
	}

	if !strings.Contains(result, "# Delete") {
		t.Fatalf("expected '# Delete' in output")
	}

	if !strings.Contains(result, "Plan: 1 to add, 2 to change, 1 to destroy") {
		t.Fatalf("expected correct summary count in output, got: %s", result)
	}
}

