func TestCompactDiffFormatterWithIndexes(t *testing.T) {
	plan := &plans.Plan{
		Changes: &plans.ChangesSrc{
			Resources: []*plans.ResourceInstanceChangeSrc{
				{
					Addr: addrs.Resource{
						Mode: addrs.ManagedResourceMode,
						Type: "aws_instance",
						Name: "example",
					}.Instance(addrs.IntKey(0)).Absolute(addrs.RootModuleInstance),
					ProviderAddr: addrs.AbsProviderConfig{
						Module:   addrs.RootModule,
						Provider: addrs.NewDefaultProvider("aws"),
					},
					ChangeSrc: plans.ChangeSrc{
						Action: plans.Create,
					},
				},
				{
					Addr: addrs.Resource{
						Mode: addrs.ManagedResourceMode,
						Type: "aws_instance",
						Name: "example",
					}.Instance(addrs.StringKey("prod")).Absolute(addrs.RootModuleInstance),
					ProviderAddr: addrs.AbsProviderConfig{
						Module:   addrs.RootModule,
						Provider: addrs.NewDefaultProvider("aws"),
					},
					ChangeSrc: plans.ChangeSrc{
						Action: plans.Create,
					},
				},
			},
		},
	}

	formatter := &CompactDiffFormatter{}
	result := formatter.Format(plan, nil)

	if !strings.Contains(result, "aws_instance.example[0]") {
		t.Fatalf("expected 'aws_instance.example[0]' in output, got: %s", result)
	}

	if !strings.Contains(result, "aws_instance.example[\"prod\"]") {
		t.Fatalf("expected 'aws_instance.example[\"prod\"]' in output, got: %s", result)
	}
}

func TestCompactDiffFormatterSkipsDeposed(t *testing.T) {
