package format

import (
	"bytes"
	"fmt"
	"sort"

	"github.com/hashicorp/terraform/internal/addrs"
	"github.com/hashicorp/terraform/internal/plans"
	"github.com/hashicorp/terraform/internal/schemarepo"
)

// CompactDiffFormatter formats a plan as a compact, summary-style diff showing
// only resource-level changes without attribute-level detail.
type CompactDiffFormatter struct{}

// Format renders a plan as a compact summary of resource changes.
// Changes are grouped by action type (Create, Update, Delete, Replace)
// and a summary count is shown at the end.
func (f *CompactDiffFormatter) Format(plan *plans.Plan, schemas *schemarepo.Schemas) string {
	if plan == nil || plan.Changes == nil {
		return ""
	}

	var buf bytes.Buffer

	// Group changes by action
	creates := []*plans.ResourceInstanceChangeSrc{}
	updates := []*plans.ResourceInstanceChangeSrc{}
	deletes := []*plans.ResourceInstanceChangeSrc{}
	replaces := []*plans.ResourceInstanceChangeSrc{}
	noop := []*plans.ResourceInstanceChangeSrc{}

	for _, change := range plan.Changes.Resources {
		// Skip deposed objects (only format the current object)
		if change.DeposedKey != "" {
			continue
		}

		switch change.Action {
		case plans.Create:
			creates = append(creates, change)
		case plans.Update:
			updates = append(updates, change)
		case plans.Delete:
			deletes = append(deletes, change)
		case plans.DeleteThenCreate, plans.CreateThenDelete:
