    17→// CompactDiffFormatter formats a plan as a compact, summary-style diff showing
    18→// only resource-level changes without attribute-level detail.
    19→type CompactDiffFormatter struct{}
    20→
    21→// Format renders a plan as a compact summary of resource changes.
    22→// Changes are grouped by action type (Create, Update, Delete, Replace)
    23→// and a summary count is shown at the end.
    24→func (f *CompactDiffFormatter) Format(plan *plans.Plan, schemas *schemarepo.Schemas) string {
    25→	if plan == nil || plan.Changes == nil {
    26→		return ""
    27→	}
    28→
    29→	var buf bytes.Buffer
    30→
    31→	// Group changes by action
    32→	creates := []*plans.ResourceInstanceChangeSrc{}
    33→	updates := []*plans.ResourceInstanceChangeSrc{}
    34→	deletes := []*plans.ResourceInstanceChangeSrc{}
    35→	replaces := []*plans.ResourceInstanceChangeSrc{}
    36→	noop := []*plans.ResourceInstanceChangeSrc{}
    37→
    38→	for _, change := range plan.Changes.Resources {
    39→		// Skip deposed objects (only format the current object)
    40→		if change.DeposedKey != states.NotDeposed {
    41→			continue
    42→		}
    43→
    44→		switch change.Action {
    45→		case plans.Create:
    46→			creates = append(creates, change)
    47→		case plans.Update:
    48→			updates = append(updates, change)
    49→		case plans.Delete:
    50→			deletes = append(deletes, change)
    51→		case plans.DeleteThenCreate, plans.CreateThenDelete:
    52→			replaces = append(replaces, change)
    53→		case plans.NoOp:
    54→			noop = append(noop, change)
    55→		default:
    56→			// Handle other actions (Read, Forget, etc.)
    57→			noop = append(noop, change)
    58→		}
    59→	}
    60→
    61→	// Sort each group for consistent output
    62→	sortChanges(creates)
    63→	sortChanges(updates)
    64→	sortChanges(deletes)
    65→	sortChanges(replaces)
    66→
    67→	// Output changes grouped by action type
    68→	if len(creates) > 0 {
    69→		buf.WriteString("# Create
")
    70→		for _, change := range creates {
    71→			buf.WriteString(fmt.Sprintf("  [+] %s
", change.Addr.String()))
    72→		}
    73→	}
    74→
    75→	if len(updates) > 0 {
    76→		buf.WriteString("# Update
")
    77→		for _, change := range updates {
    78→			buf.WriteString(fmt.Sprintf("  [~] %s
", change.Addr.String()))
    79→		}
    80→	}
    81→
    82→	if len(replaces) > 0 {
    83→		buf.WriteString("# Replace
")
    84→		for _, change := range replaces {
    85→			buf.WriteString(fmt.Sprintf("  [-/+] %s
", change.Addr.String()))
    86→		}
    87→	}
    88→
    89→	if len(deletes) > 0 {
    90→		buf.WriteString("# Delete
")
    91→		for _, change := range deletes {
    92→			buf.WriteString(fmt.Sprintf("  [-] %s
", change.Addr.String()))
    93→		}
    94→	}
    95→
    96→	// Summary count
    97→	total := len(creates) + len(updates) + len(replaces) + len(deletes)
    98→	if total > 0 {
    99→		buf.WriteString("
")
   100→		buf.WriteString(fmt.Sprintf("Plan: %d to add, %d to change, %d to destroy.
",
   101→			len(creates), len(updates)+len(replaces), len(deletes)))
   102→	}
   103→
   104→	return buf.String()
   105→}
