   107→// sortChanges sorts changes by their address for consistent output
   108→func sortChanges(changes []*plans.ResourceInstanceChangeSrc) {
   109→	sort.Slice(changes, func(i, j int) bool {
   110→		return changes[i].Addr.String() < changes[j].Addr.String()
   111→	})
   112→}
